import pandas as pd
from datetime import datetime, timedelta

class AccountingReport:
    def __init__(self, data_source):
        self.data_source = data_source
        self.data = self.load_data()

    def load_data(self):
        # Simulate loading data from an accounting system
        # In a real scenario, this would connect to QuickBooks, Sage, etc.
        return pd.read_csv(self.data_source)

    def generate_report(self, start_date, end_date, report_type):
        filtered_data = self.filter_data(start_date, end_date)
        if report_type == 'monthly':
            return self.generate_monthly_report(filtered_data)
        elif report_type == 'quarterly':
            return self.generate_quarterly_report(filtered_data)
        elif report_type == 'yearly':
            return self.generate_yearly_report(filtered_data)
        else:
            raise ValueError("Invalid report type. Choose 'monthly', 'quarterly', or 'yearly'.")

    def filter_data(self, start_date, end_date):
        self.data['Date'] = pd.to_datetime(self.data['Date'])
        return self.data[(self.data['Date'] >= start_date) & (self.data['Date'] <= end_date)]

    def generate_monthly_report(self, data):
        return data.resample('M', on='Date').sum()

    def generate_quarterly_report(self, data):
        return data.resample('Q', on='Date').sum()

    def generate_yearly_report(self, data):
        return data.resample('Y', on='Date').sum()

if __name__ == "__main__":
    data_source = 'accounting_data.csv'  # Path to the CSV file containing accounting data
    report_generator = AccountingReport(data_source)

    # Example usage
    start_date = datetime(2023, 1, 1)
    end_date = datetime(2023, 12, 31)
    report_type = 'monthly'  # Change to 'quarterly' or 'yearly' as needed

    report = report_generator.generate_report(start_date, end_date, report_type)
    print(report)

