import pandas as pd
from datetime import datetime

class AccountingReport:
    def __init__(self, data_source):
        self.data_source = data_source
        self.data = self.load_data()

    def load_data(self):
        # Simulate loading data from an accounting system
        # In a real scenario, this would connect to QuickBooks, Sage, etc.
        return pd.read_csv(self.data_source)

    def generate_report(self, period='month', start_date=None, end_date=None):
        if start_date is None or end_date is None:
            end_date = datetime.now()
            if period == 'month':
                start_date = end_date.replace(day=1)
            elif period == 'quarter':
                start_date = end_date - pd.DateOffset(months=3)
            elif period == 'year':
                start_date = end_date.replace(month=1, day=1)

        filtered_data = self.filter_data(start_date, end_date)
        report = self.summarize_data(filtered_data)
        return report

    def filter_data(self, start_date, end_date):
        self.data['Date'] = pd.to_datetime(self.data['Date'])
        return self.data[(self.data['Date'] >= start_date) & (self.data['Date'] <= end_date)]

    def summarize_data(self, filtered_data):
        summary = {
            'Total Sales': filtered_data['Sales'].sum(),
            'Total Expenses': filtered_data['Expenses'].sum(),
            'Net Profit': filtered_data['Sales'].sum() - filtered_data['Expenses'].sum(),
            'Total Transactions': filtered_data.shape[0]
        }
        return summary

# Example usage
if __name__ == "__main__":
    report_generator = AccountingReport('accounting_data.csv')
    monthly_report = report_generator.generate_report(period='month')
    quarterly_report = report_generator.generate_report(period='quarter')
    yearly_report = report_generator.generate_report(period='year')

    print("Monthly Report:", monthly_report)
    print("Quarterly Report:", quarterly_report)
    print("Yearly Report:", yearly_report)

