import pandas as pd
import numpy as np
from datetime import datetime, timedelta

class AccountingReportGenerator:
    def __init__(self, start_date, end_date):
        self.start_date = start_date
        self.end_date = end_date
        self.data = self.generate_sample_data()

    def generate_sample_data(self):
        dates = pd.date_range(self.start_date, self.end_date, freq='D')
        sales = np.random.randint(100, 1000, size=len(dates))
        expenses = np.random.randint(50, 500, size=len(dates))
        return pd.DataFrame({'Date': dates, 'Sales': sales, 'Expenses': expenses})

    def generate_report(self, period='monthly'):
        if period == 'monthly':
            report = self.data.resample('M', on='Date').sum()
        elif period == 'quarterly':
            report = self.data.resample('Q', on='Date').sum()
        elif period == 'yearly':
            report = self.data.resample('Y', on='Date').sum()
        else:
            raise ValueError("Invalid period. Choose 'monthly', 'quarterly', or 'yearly'.")

        report['Profit'] = report['Sales'] - report['Expenses']
        return report

    def save_report(self, report, filename):
        report.to_csv(filename)
        print(f"Report saved to {filename}")

if __name__ == "__main__":
    start_date = datetime(2022, 1, 1)
    end_date = datetime(2023, 12, 31)
    report_generator = AccountingReportGenerator(start_date, end_date)

    period = input("Enter the reporting period (monthly, quarterly, yearly): ").strip().lower()
    report = report_generator.generate_report(period)
    print(report)

    filename = input("Enter the filename to save the report (e.g., report.csv): ").strip()
    report_generator.save_report(report, filename)

