    def __init__(self, accounting_system):
        self.accounting_system = accounting_system
        self.customizable_fields = {
            'income_statement': ['revenue', 'expenses', 'net_income'],
            'balance_sheet': ['assets', 'liabilities', 'equity'],
            'cash_flow_statement': ['operating_activities', 'investing_activities', 'financing_activities']
        }

    def generate_report(self, report_type, customization_options):
        if report_type not in self.customizable_fields:
            raise ValueError("Invalid report type. Choose from: " + ", ".join(self.customizable_fields.keys()))

        report_data = self.fetch_data(report_type)
        report_data = self.customize_report(report_data, customization_options)
        return report_data

    def fetch_data(self, report_type):
        # Simulate fetching data from the accounting system
        data = {
            'income_statement': {
                'revenue': 100000,
                'expenses': 50000,
                'net_income': 50000
            },
            'balance_sheet': {
                'assets': 200000,
                'liabilities': 100000,
                'equity': 100000
            },
            'cash_flow_statement': {
                'operating_activities': 30000,
                'investing_activities': -10000,
                'financing_activities': 20000
            }
        }
        return data[report_type]

    def customize_report(self, report_data, customization_options):
        customized_data = {}
        for field in self.customizable_fields[report_data]:
            if field in customization_options:
                customized_data[field] = customization_options[field]
            else:
                customized_data[field] = report_data[field]
        return customized_data

